import os, sys, glob, json, subprocess
import site
site.addsitedir('/kaggle/usr/lib/notebooks/ryanholbrook/nvidia-utility-script/nvidia_cutlass_dsl/python_packages/')
import torch

ngpu = torch.cuda.device_count()
props0 = torch.cuda.get_device_properties(0)
cc = props0.major + props0.minor/10
vram_total_gb = sum(torch.cuda.get_device_properties(i).total_memory for i in range(ngpu)) / 1024**3
print(f'CUDA devices: {ngpu}')
for i in range(ngpu):
    p = torch.cuda.get_device_properties(i)
    print(f'  GPU{i}: {p.name} | {p.total_memory/1024**3:.1f} GB | sm_{p.major}{p.minor}')
print(f'Total VRAM: {vram_total_gb:.1f} GB')
assert cc >= 7.0, f'GPU sm_{props0.major}{props0.minor} INCOMPATIBLE (need >= sm_70). Pick T4 x2 or RTX Pro 6000.'

# Find the offline wheel dir from the nctuan dataset
OFFLINE_DIR = None
for cand in glob.glob('/kaggle/input/*nvidia-offline-packages*/offline_packages'):
    OFFLINE_DIR = cand; break
if not OFFLINE_DIR:
    for cand in glob.glob('/kaggle/input/*/offline_packages'):
        OFFLINE_DIR = cand; break
print('OFFLINE_DIR:', OFFLINE_DIR)

# If we need 4-bit (VRAM < 60GB) install bitsandbytes from the local wheel
if vram_total_gb < 60:
    try:
        import bitsandbytes; print('bnb already present', bitsandbytes.__version__)
    except ImportError:
        if OFFLINE_DIR:
            print('installing bitsandbytes from local wheel (OFFLINE)...')
            r = subprocess.run([sys.executable,'-m','pip','install','--no-index',
                                '--find-links', OFFLINE_DIR, 'bitsandbytes'],
                               capture_output=True, text=True)
            print(f'  rc={r.returncode}')
            if r.returncode != 0: print('  stderr:', r.stderr[-1200:])
            else: print('  stdout:', r.stdout[-400:])
            try:
                import importlib; importlib.invalidate_caches()
                import bitsandbytes; print('bnb installed', bitsandbytes.__version__)
            except Exception as e: print('bnb import after install:', e)
        else:
            raise RuntimeError('No OFFLINE_DIR found. Attach dataset nctuan/nvidia-offline-packages-nemotron via Add Input.')

# Locate competition train.csv
import csv
cands = glob.glob('/kaggle/input/*/train.csv')
print('train.csv:', cands)
train_data = []
if cands:
    with open(cands[0], encoding='utf-8') as f:
        for row in csv.DictReader(f):
            q = row.get('prompt') or row.get('question') or ''
            a = row.get('answer') or row.get('completion') or ''
            if q and a: train_data.append({'prompt': q, 'completion': str(a)})
            if len(train_data) >= 50: break
print('loaded', len(train_data), 'training rows')

os.makedirs('/kaggle/working/offload', exist_ok=True)
